(14,1,'2026-01-26 11:44:59','2026-01-26 10:44:59','.site-description {\n	max-width: 220px;\n}\n\n/** HEADER **/\n\n.header-contact > div {\n	padding-left: 30px !important;\n}\n\n.header-contact > div > svg {\n	display: none;\n	width: 0;\n	position: unset;\n}\n\n.header-contact > div:last-child > .content {\n	display: block;\n	max-width: 150px;\n	white-space: normal;\n}\n\n/** BANNER **/\n\n.site-banner .btn {\n	font-size: 0.8em;\n}\n\n/** SERVICES **/\n\n#service_section_two {\n	padding-bottom: 60px;\n}\n\n/** CTA **/\n\n.cta-section .text-holder {\n	margin-top: 40px;\n	max-width: unset !important;\n}\n\n.cta-section .text-holder > p {\n	margin-top: 10px;\n}\n\n.cta-section .button-wrap {\n	margin-top: 60px;\n}\n\n.cta-section .button-wrap .btn-cta {\n	font-size: 0.8em;\n}','blossom-spa','','publish','closed','closed','','blossom-spa','','','2026-01-26 14:57:52','2026-01-26 13:57:52','',0,'http://localhost:8080/?p=14',0,'custom_css','',0),
