sur la sph\\u00e8re digestive.\",\n        \"type\": \"theme_mod\",\n        \"user_id\": 1,\n        \"date_modified_gmt\": \"2026-01-31 17:28:45\"\n    }\n}','','','trash','closed','closed','','1048f43d-2a19-4d13-9c2f-83e02a9a67a4','','','2026-01-31 18:28:45','2026-01-31 17:28:45','',0,'http://localhost:8080/1048f43d-2a19-4d13-9c2f-83e02a9a67a4/',0,'customize_changeset','',0),
