_session-media\"><!-- wp:image {\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"appointment-cta__image\"} -->\n<figure class=\"wp-block-image size-full appointment-cta__image\"><img src=\"http://localhost:8080/wp-content/themes/my-theme/assets/images/pattern-placeholder-400.svg\" alt=\"\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->','Test','','inherit','closed','closed','','587-revision-v1','','','2026-02-13 16:06:37','2026-02-13 15:06:37','',587,'http://localhost:8080/?p=642',0,'revision','',0),
