graph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"align\":\"full\",\"className\":\"appointment-cta__session-band\\u002d\\u002dsecondary appointment-cta__session-band\\u002d\\u002dclinic\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group alignfull appointment-cta__session-band--secondary appointment-cta__session-band--clinic\"><!-- wp:group {\"className\":\"appointment-cta__session\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group appointment-cta__session\"><!-- wp:columns {\"verticalAlignment\":\"top\",\"className\":\"appointment-cta__session-columns\"} -->\n<div class=\"wp-block-columns are-vertically-aligned-top appointment-cta__session-columns\"><!-- wp:column {\"verticalAlignment\":\"top\",\"className\":\"appointment-cta__session-content\"} -->\n<div class=\"wp-block-column is-vertically-aligned-top appointment-cta__session-content\"><!-- wp:heading {\"className\":\"appointment-cta__session-content__title\"} -->\n<h2 class=\"wp-block-heading appointment-cta__session-content__title\"><span><svg xmlns=\"http://www.w3.org/2000/svg\" width=\"24\" height=\"24\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\" class=\"lucide lucide-heart w-6 h-6 text-primary\"><path d=\"M19 14c1.49-1.46 3-3.21 3-5.5A5.5 5.5 0 0 0 16.5 3c-1.76 0-3 .5-4.5 2-1.5-1.5-2.74-2-4.5-2A5.5 5.5 0 0 0 2 8.5c0 2.3 1.5 4.05 3 5.5l7 7Z\"></path></svg></span>Séance au cabinet</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Prix d\'une séance : 50 €</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Accueil au cabinet sur rendez-vous uniquement. Merci d’arriver 5 minutes avant l’horaire prévu pour un échange serein.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Les séances durent environ 30 minutes. Un temps d’échange en début de séance permet d’adapter l’accompagnement.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>