(832,1,'2026-02-23 13:43:31','2026-02-23 12:43:31','<!-- wp:group {\"tagName\":\"section\",\"align\":\"full\",\"className\":\"pattern-pains-intro\",\"layout\":{\"type\":\"default\"}} -->\n<section class=\"wp-block-group alignfull pattern-pains-intro\"><!-- wp:group {\"className\":\"pattern-pains-intro__wrapper\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group pattern-pains-intro__wrapper\"><!-- wp:heading {\"level\":1} -->\n<h1 class=\"wp-block-heading\">À propos des séances</h1>\n<!-- /wp:heading -->\n\n<!-- wp:group {\"className\":\"pattern-pains-intro__content\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group pattern-pains-intro__content\"><!-- wp:paragraph {\"className\":\"pattern-pains-intro__text\"} -->\n<p class=\"pattern-pains-intro__text\">Lors de la première séance, nous échangeons sur le problème rencontré, vos ressentis, votre état général, vos antécédents médicaux et les traitements en cours. Les séances durent en moyenne 30 minutes.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"className\":\"pattern-pains-intro__text\"} -->\n<p class=\"pattern-pains-intro__text\">Le traitement peut s’étaler sur plusieurs séances et varie en fonction de l’âge de la personne et de l’ancienneté du problème.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"className\":\"pattern-pains-intro__text\"} -->\n<p class=\"pattern-pains-intro__text\">Les soins se déroulent toujours habillé, sans manipulation et en présence d\'un adulte pour les personnes mineures.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"className\":\"pattern-pains-intro__sessions-intro\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group pattern-pains-intro__sessions-intro\"><!-- wp:heading {\"className\":\"pattern-pains-intro__sessions-title\"} -->\n<h2 class=\"wp-block-heading pattern-pains-intro__sessions-title\">La séance qui vous convient</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"className\":\"pattern-pains-intro__sessions-text\"} -->\n<p class=\"pattern-pains-intro__sessions-text\">Chaque accompagnement est personnalisé. Choisissez une séance au cabinet, à distance ou à domicile selon votre situation, votre disponibilité et vos besoins. Nous échangeons ensemble pour retenir la formule la plus adaptée.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"className\":\"pattern-pains-intro__sessions\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group pattern-pains-intro__sessions\"><!-- wp:group {\"className\":\"pattern-pains-intro__session-card\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group pattern-pains-intro__session-card\"><!-- wp:heading {\"level\":3,\"className\":\"pattern-pains-intro__session-title\"} -->\n<h3 class=\"wp-block-heading pattern-pains-intro__session-title\"><span><svg xmlns=\"http://www.w3.org/2000/svg\" width=\"24\" height=\"24\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\" class=\"lucide lucide-heart w-6 h-6 text-primary\"><path d=\"M19 14c1.49-1.46 3-3.21 3-5.5A5.5 5.5 0 0 0 16.5 3c-1.76 0-3 .5-4.5 2-1.5-1.5-2.74-2-4.5-2A5.5 5.5 0 0 0 2 8.5c0 2.3 1.5 4.05 3 5.5l7 7Z\"></path></svg></span>Séance au cabinet</h3>\n<!-- /wp:heading --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"className\":\"pattern-pains-intro__session-card\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group pattern-pains-intro__session-card\"><!-- wp:heading {\"level\":3,\"className\":\"pattern-pains-intro__session-title\"} -->\n<h3 class=\"wp-block-heading pattern-pains-intro__session-title\"><span><svg xmlns=\"http://www.w3.org/2000/svg\" width=\"24\" height=\"24\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\" class=\"lucide lucide-monitor-smartphone\"><rect width=\"20\" height=\"14\" x=\"2\" y=\"4\" rx=\"2\"></rect><path d=\"M12 18v2\"></path><path d=\"M8 22h8\"></path><rect width=\"6\" height=\"8\" x=\"16\" y=\"12\" rx=\"1\"></rect></svg></span>Séance à distance</h3>\n<!-- /wp:heading --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"className\":\"pattern-pains-intro__session-card\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group pattern-pains-intro__session-card\"><!-- wp:heading {\"level\":3,\"className\":\"pattern-pains-intro__session-title\"} -->\n<h3 class=\"wp-block-heading pattern-pains-intro__session-title\"><span><svg xmlns=\"http://www.w3.org/2000/svg\" width=\"24\" height=\"24\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\" class=\"lucide lucide-house\"><path d=\"m3 9 9-7 9 7\"></path><path d=\"M9 22V12h6v10\"></path></svg></span>Séance à domicile</h3>\n<!-- /wp:heading --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></section>\n<!-- /wp:group -->\n\n<!-- wp:group {\"tagName\":\"section\",\"align\":\"full\",\"className\":\"pattern-pains\",\"layout\":{\"type\":\"default\"}} -->\n<section class=\"wp-block-group alignfull pattern-pains\"><!-- wp:group {\"className\":\"pattern-pains__wrapper\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group pattern-pains__wrapper\"><!-- wp:heading {\"className\":\"pattern-pains__title\"} -->\n<h2 class=\"wp-block-heading pattern-pains__title\">Les douleurs que je peux soulager</h2>\n<!-- /wp:heading -->\n\n<!-- wp:group {\"className\":\"pattern-pains__top\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group pattern-pains__top\"><!-- wp:group {\"className\":\"pattern-pains__content\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group pattern-pains__content\"><!-- wp:list {\"className\":\"pattern-pains__list\"} -->\n<ul class=\"wp-block-list pattern-pains__list\"><!-- wp:list-item -->\n<li>Douleurs articulaires et musculaires</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Problèmes de sommeil, de fatigue ou de stress</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Maladies de peau (eczéma, psoriasis, verrues...)</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Brûlures</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Troubles digestifs</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Migraines et vertiges</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Problèmes respiratoires et allergiques</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Effets secondaires des radiothérapies et chimiothérapies</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"className\":\"pattern-pains__media\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group pattern-pains__media\"><!-- wp:image {\"id\":778,\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"pattern-pains__image\"} -->\n<figure class=\"wp-block-image size-full pattern-pains__image\"><img src=\"http://localhost:8080/wp-content/uploads/2026/02/AIMER-GUERIR-2020-AL-175.avif\" alt=\"\" class=\"wp-image-778\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"className\":\"pattern-pains__actions\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group pattern-pains__actions\"><!-- wp:group {\"className\":\"pattern-pains__disclaimer\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group pattern-pains__disclaimer\"><!-- wp:paragraph {\"className\":\"pattern-pains__disclaimer-text\"} -->\n<p class=\"pattern-pains__disclaimer-text\">Aucune des prestations proposées ici ne dispense d’une visite chez votre médecin.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"className\":\"pattern-pains__disclaimer-text\"} -->\n<p class=\"pattern-pains__disclaimer-text\">Si vous suivez un traitement médical, il doit impérativement être poursuivi. Vous ne devez jamais modifier ou arrêter un traitement en cours sans l’avis de votre médecin.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"className\":\"pattern-pains__disclaimer-text\"} -->\n<p class=\"pattern-pains__disclaimer-text\">Les séances de magnétisme viennent en complément et peuvent faciliter l’action de vos traitements médicaux ou de votre accompagnement psychologique. Elles ne peuvent en aucun cas les remplacer.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></section>\n<!-- /wp:group -->\n\n<!-- wp:group {\"metadata\":{\"categories\":[\"my-theme\"],\"patternName\":\"my-theme/cta\",\"name\":\"Appel à l\'action\"},\"align\":\"full\",\"className\":\"cta\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group alignfull cta\"><!-- wp:group {\"className\":\"cta__wrapper\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group cta__wrapper\"><!-- wp:heading {\"className\":\"cta__title\"} -->\n<h2 class=\"wp-block-heading cta__title\">Prendre rendez-vous</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"className\":\"cta__subtitle\"} -->\n<p class=\"cta__subtitle\">Un premier échange pour faire le point et planifier votre séance.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"#\">Réserver une séance</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->','Les séances','','inherit','closed','closed','','719-revision-v1','','','2026-02-23 13:43:31','2026-02-23 12:43:31','',719,'http://localhost:8080/?p=832',0,'revision','',0),
(833,1,'2026-02-23 13:53:17','2026-02-23 12:53:17','<!-- wp:group {\"metadata\":{\"categories\":[\"my-theme\"],\"patternName\":\"my-theme/appointment-cta\",\"name\":\"Prendre rendez-vous\"},\"align\":\"wide\",\"className\":\"pattern-appointment-cta\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group alignwide pattern-appointment-cta\"><!-- wp:group {\"className\":\"appointment-cta__header\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group appointment-cta__header\"><!-- wp:heading {\"level\":1} -->\n<h1 class=\"wp-block-heading\">Horaires d\'ouverture du cabinet</h1>\n<!-- /wp:heading -->\n\n<!-- wp:group {\"className\":\"appointment-cta__schedules\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group appointment-cta__schedules\"><!-- wp:paragraph -->\n<p>Du lundi au vendredi de 08:30 à 13:00 et de 14:00 à 19:00</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Le samedi de 09:00 à 12:00</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"#\">Réserver une séance</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"className\":\"appointment-cta__info\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group appointment-cta__info\"><!-- wp:group {\"className\":\"appointment-cta__card\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group appointment-cta__card\"><!-- wp:heading {\"level\":3,\"className\":\"appointment-cta__card__title\"} -->\n<h3 class=\"wp-block-heading appointment-cta__card__title\"><span><svg xmlns=\"http://www.w3.org/2000/svg\" width=\"24\" height=\"24\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\" class=\"lucide lucide-alert-triangle\"><path d=\"M10.29 3.86 1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0Z\"></path><line x1=\"12\" x2=\"12\" y1=\"9\" y2=\"13\"></line><line x1=\"12\" x2=\"12.01\" y1=\"17\" y2=\"17\"></line></svg></span>Urgences</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>En cas d’urgence, n’hésitez pas à me contacter au 06 95 64 54 76. Je mettrais alors tout en œuvre pour vous recevoir le plus rapidement possible.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"className\":\"appointment-cta__card\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group appointment-cta__card\"><!-- wp:heading {\"level\":3,\"className\":\"appointment-cta__card__title\"} -->\n<h3 class=\"wp-block-heading appointment-cta__card__title\"><span><svg xmlns=\"http://www.w3.org/2000/svg\" width=\"24\" height=\"24\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\" class=\"lucide lucide-calendar-x\"><rect x=\"3\" y=\"4\" width=\"18\" height=\"18\" rx=\"2\" ry=\"2\"></rect><line x1=\"16\" x2=\"8\" y1=\"13\" y2=\"19\"></line><line x1=\"8\" x2=\"16\" y1=\"13\" y2=\"19\"></line><line x1=\"8\" y1=\"2\" y2=\"6\" x2=\"8\"></line><line x1=\"16\" y1=\"2\" y2=\"6\" x2=\"16\"></line><line x1=\"3\" y1=\"10\" y2=\"10\" x2=\"21\"></line></svg></span>Annulation</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Je vous remercie par avance de l’égard que vous porterez sur mon organisation logistique en annulant votre séance au plus tard 48 heures avant votre rendez-vous.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"align\":\"full\",\"className\":\"appointment-cta__session-band\\u002d\\u002dsecondary appointment-cta__session-band\\u002d\\u002dclinic\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group alignfull appointment-cta__session-band--secondary appointment-cta__session-band--clinic\"><!-- wp:group {\"className\":\"appointment-cta__session\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group appointment-cta__session\"><!-- wp:columns {\"verticalAlignment\":\"top\",\"className\":\"appointment-cta__session-columns\"} -->\n<div class=\"wp-block-columns are-vertically-aligned-top appointment-cta__session-columns\"><!-- wp:column {\"verticalAlignment\":\"top\",\"className\":\"appointment-cta__session-content\"} -->\n<div class=\"wp-block-column is-vertically-aligned-top appointment-cta__session-content\"><!-- wp:heading {\"className\":\"appointment-cta__session-content__title\"} -->\n<h2 class=\"wp-block-heading appointment-cta__session-content__title\"><span><svg xmlns=\"http://www.w3.org/2000/svg\" width=\"24\" height=\"24\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\" class=\"lucide lucide-heart w-6 h-6 text-primary\"><path d=\"M19 14c1.49-1.46 3-3.21 3-5.5A5.5 5.5 0 0 0 16.5 3c-1.76 0-3 .5-4.5 2-1.5-1.5-2.74-2-4.5-2A5.5 5.5 0 0 0 2 8.5c0 2.3 1.5 4.05 3 5.5l7 7Z\"></path></svg></span>Séance au cabinet</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Prix d\'une séance : 50 €</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Accueil au cabinet sur rendez-vous uniquement. Merci d’arriver 5 minutes avant l’horaire prévu pour un échange serein.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Les séances durent environ 30 minutes. Un temps d’échange en début de séance permet d’adapter l’accompagnement.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Règlement en espèces, par carte bancaire ou chèque à l’ordre de « Aimer Guérir »</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"verticalAlignment\":\"top\",\"className\":\"appointment-cta__session-media\"} -->\n<div class=\"wp-block-column is-vertically-aligned-top appointment-cta__session-media\"><!-- wp:html -->\n<div class=\"appointment-cta__map\">\n            <iframe src=\"https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d2612.811945255373!2d1.473684077475943!3d49.09021378436306!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x47e6cbc2d9e0c1bb%3A0x66a52c1a90689d22!2s24%20Rue%20de%20l&#39;Horloge%2C%2027200%20Vernon!5e0!3m2!1sfr!2sfr!4v1770993525666!5m2!1sfr!2sfr\" width=\"600\" height=\"450\" style=\"border:0;\" allowfullscreen=\"\" loading=\"lazy\" referrerpolicy=\"no-referrer-when-downgrade\"></iframe>\n          </div>\n<!-- /wp:html --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:group {\"className\":\"appointment-cta__session-gallery-row\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group appointment-cta__session-gallery-row\"><!-- wp:columns {\"className\":\"appointment-cta__session-gallery\"} -->\n<div class=\"wp-block-columns appointment-cta__session-gallery\"><!-- wp:column {\"width\":\"33.33%\",\"className\":\"appointment-cta__session-gallery-item\"} -->\n<div class=\"wp-block-column appointment-cta__session-gallery-item\" style=\"flex-basis:33.33%\"><!-- wp:image {\"id\":623,\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"appointment-cta__session-image\"} -->\n<figure class=\"wp-block-image size-full appointment-cta__session-image\"><img src=\"http://localhost:8080/wp-content/uploads/2026/02/2022-05-07-Nouveau-local-AIMER-GUERIR.avif\" alt=\"Cabinet vu de la rue\" class=\"wp-image-623\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"width\":\"33.33%\",\"className\":\"appointment-cta__session-gallery-item\"} -->\n<div class=\"wp-block-column appointment-cta__session-gallery-item\" style=\"flex-basis:33.33%\"><!-- wp:image {\"id\":625,\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"appointment-cta__session-image\"} -->\n<figure class=\"wp-block-image size-full appointment-cta__session-image\"><img src=\"http://localhost:8080/wp-content/uploads/2026/02/Horloge-02-BD.avif\" alt=\"Salle d\'attente cabinet Christophe Rebours\" class=\"wp-image-625\"/><figcaption class=\"wp-element-caption\">Salle d\'attente cabinet Christophe Rebours</figcaption></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"width\":\"33.33%\",\"className\":\"appointment-cta__session-gallery-item\"} -->\n<div class=\"wp-block-column appointment-cta__session-gallery-item\" style=\"flex-basis:33.33%\"><!-- wp:image {\"id\":624,\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"appointment-cta__session-image\"} -->\n<figure class=\"wp-block-image size-full appointment-cta__session-image\"><img src=\"http://localhost:8080/wp-content/uploads/2026/02/Horloge-03-BD.avif\" alt=\"Cabinet Christophe Rebours\" class=\"wp-image-624\"/><figcaption class=\"wp-element-caption\">Cabinet Christophe Rebours</figcaption></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"align\":\"full\",\"className\":\"appointment-cta__session-band\\u002d\\u002dprimary\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group alignfull appointment-cta__session-band--primary\"><!-- wp:group {\"className\":\"appointment-cta__session\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group appointment-cta__session\"><!-- wp:columns {\"verticalAlignment\":\"top\",\"className\":\"appointment-cta__session-columns\"} -->\n<div class=\"wp-block-columns are-vertically-aligned-top appointment-cta__session-columns\"><!-- wp:column {\"verticalAlignment\":\"top\",\"className\":\"appointment-cta__session-content\"} -->\n<div class=\"wp-block-column is-vertically-aligned-top appointment-cta__session-content\"><!-- wp:heading {\"className\":\"appointment-cta__session-content__title\"} -->\n<h2 class=\"wp-block-heading appointment-cta__session-content__title\"><span><svg xmlns=\"http://www.w3.org/2000/svg\" width=\"24\" height=\"24\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\" class=\"lucide lucide-monitor-smartphone\"><rect width=\"20\" height=\"14\" x=\"2\" y=\"4\" rx=\"2\"></rect><path d=\"M12 18v2\"></path><path d=\"M8 22h8\"></path><rect width=\"6\" height=\"8\" x=\"16\" y=\"12\" rx=\"1\"></rect></svg></span>Séance à distance</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Prix d\'une séance : 50 €</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Je vous remercie de m\'adresser à l\'adresse email contact@aimerguerir.com une photo de votre visage (sans lunettes de soleil) afin que je puisse me connecter à votre champ énergétique.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>A l\'heure convenue, je vous contacterai par téléphone afin que vous m\'exposiez votre problématique. Puis, je réaliserai le travail énergétique nécessaire. Préparer un kit main libre si vous utilisez un portable.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Le paiement s\'effectue par carte bancaire AVANT la séance. Une séance non réglée ne peut être honorée.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"verticalAlignment\":\"top\",\"className\":\"appointment-cta__session-media\"} -->\n<div class=\"wp-block-column is-vertically-aligned-top appointment-cta__session-media\"><!-- wp:image {\"id\":627,\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"appointment-cta__image\"} -->\n<figure class=\"wp-block-image size-full appointment-cta__image\"><img src=\"http://localhost:8080/wp-content/uploads/2026/02/AIMER-GUERIR-2020-AL-200-scaled.jpg\" alt=\"\" class=\"wp-image-627\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"align\":\"full\",\"className\":\"appointment-cta__session-band\\u002d\\u002dsecondary\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group alignfull appointment-cta__session-band--secondary\"><!-- wp:group {\"className\":\"appointment-cta__session\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group appointment-cta__session\"><!-- wp:columns {\"verticalAlignment\":\"top\",\"className\":\"appointment-cta__session-columns\"} -->\n<div class=\"wp-block-columns are-vertically-aligned-top appointment-cta__session-columns\"><!-- wp:column {\"verticalAlignment\":\"top\",\"className\":\"appointment-cta__session-content\"} -->\n<div class=\"wp-block-column is-vertically-aligned-top appointment-cta__session-content\"><!-- wp:heading {\"className\":\"appointment-cta__session-content__title\"} -->\n<h2 class=\"wp-block-heading appointment-cta__session-content__title\"><span><svg xmlns=\"http://www.w3.org/2000/svg\" width=\"24\" height=\"24\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\" class=\"lucide lucide-house\"><path d=\"m3 9 9-7 9 7\"></path><path d=\"M9 22V12h6v10\"></path></svg></span>Séance à domicile</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Prix d\'une séance : 70 €</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Je me déplace uniquement sur la Commune de Vernon pour les personnes ne pouvant pas venir au cabinet. Réservations par téléphone au 06 95 64 54 76.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Le paiement peut se faire en espèces ou par chèque à l\'ordre de \"AIMER GUÉRIR\"</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Je me présenterai à l\'heure convenue au domicile du patient. Durée d’une séance : environ 30 minutes</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Merci de réserver pour le bon déroulement de la séance un espace calme et propre.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"verticalAlignment\":\"top\",\"className\":\"appointment-cta__session-media\"} -->\n<div class=\"wp-block-column is-vertically-aligned-top appointment-cta__session-media\"><!-- wp:image {\"id\":626,\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"appointment-cta__image\"} -->\n<figure class=\"wp-block-image size-full appointment-cta__image\"><img src=\"http://localhost:8080/wp-content/uploads/2026/02/AIMER-GUERIR-2020-AL-128.jpg\" alt=\"\" class=\"wp-image-626\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"metadata\":{\"categories\":[\"my-theme\"],\"patternName\":\"my-theme/cta\",\"name\":\"Appel à l\'action\"},\"align\":\"full\",\"className\":\"cta\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group alignfull cta\"><!-- wp:group {\"metadata\":{\"categories\":[\"my-theme\"],\"patternName\":\"my-theme/cta\",\"name\":\"Appel à l\'action\"},\"align\":\"full\",\"className\":\"cta\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group alignfull cta\"><!-- wp:group {\"className\":\"cta__wrapper\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group cta__wrapper\"><!-- wp:heading {\"className\":\"cta__title\"} -->\n<h2 class=\"wp-block-heading cta__title\">Prendre rendez-vous</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"className\":\"cta__subtitle\"} -->\n<p class=\"cta__subtitle\">Un premier échange pour faire le point et planifier votre séance.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"#\">Réserver une séance</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->','Prendre rendez-vous','','inherit','closed','closed','','587-revision-v1','','','2026-02-23 13:53:17','2026-02-23 12:53:17','',587,'http://localhost:8080/?p=833',0,'revision','',0),
(834,1,'2026-02-23 13:54:35','2026-02-23 12:54:35','<!-- wp:group {\"metadata\":{\"categories\":[\"my-theme\"],\"patternName\":\"my-theme/appointment-cta\",\"name\":\"Prendre rendez-vous\"},\"align\":\"wide\",\"className\":\"pattern-appointment-cta\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group alignwide pattern-appointment-cta\"><!-- wp:group {\"className\":\"appointment-cta__header\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group appointment-cta__header\"><!-- wp:heading {\"level\":1} -->\n<h1 class=\"wp-block-heading\">Horaires d\'ouverture du cabinet</h1>\n<!-- /wp:heading -->\n\n<!-- wp:group {\"className\":\"appointment-cta__schedules\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group appointment-cta__schedules\"><!-- wp:paragraph -->\n<p>Du lundi au vendredi de 08:30 à 13:00 et de 14:00 à 19:00</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Le samedi de 09:00 à 12:00</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"#\">Réserver une séance</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"className\":\"appointment-cta__info\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group appointment-cta__info\"><!-- wp:group {\"className\":\"appointment-cta__card\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group appointment-cta__card\"><!-- wp:heading {\"level\":3,\"className\":\"appointment-cta__card__title\"} -->\n<h3 class=\"wp-block-heading appointment-cta__card__title\"><span><svg xmlns=\"http://www.w3.org/2000/svg\" width=\"24\" height=\"24\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\" class=\"lucide lucide-alert-triangle\"><path d=\"M10.29 3.86 1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0Z\"></path><line x1=\"12\" x2=\"12\" y1=\"9\" y2=\"13\"></line><line x1=\"12\" x2=\"12.01\" y1=\"17\" y2=\"17\"></line></svg></span>Urgences</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>En cas d’urgence, n’hésitez pas à me contacter au 06 95 64 54 76. Je mettrais alors tout en œuvre pour vous recevoir le plus rapidement possible.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"className\":\"appointment-cta__card\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group appointment-cta__card\"><!-- wp:heading {\"level\":3,\"className\":\"appointment-cta__card__title\"} -->\n<h3 class=\"wp-block-heading appointment-cta__card__title\"><span><svg xmlns=\"http://www.w3.org/2000/svg\" width=\"24\" height=\"24\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\" class=\"lucide lucide-calendar-x\"><rect x=\"3\" y=\"4\" width=\"18\" height=\"18\" rx=\"2\" ry=\"2\"></rect><line x1=\"16\" x2=\"8\" y1=\"13\" y2=\"19\"></line><line x1=\"8\" x2=\"16\" y1=\"13\" y2=\"19\"></line><line x1=\"8\" y1=\"2\" y2=\"6\" x2=\"8\"></line><line x1=\"16\" y1=\"2\" y2=\"6\" x2=\"16\"></line><line x1=\"3\" y1=\"10\" y2=\"10\" x2=\"21\"></line></svg></span>Annulation</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Je vous remercie par avance de l’égard que vous porterez sur mon organisation logistique en annulant votre séance au plus tard 48 heures avant votre rendez-vous.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"align\":\"full\",\"className\":\"appointment-cta__session-band\\u002d\\u002dsecondary appointment-cta__session-band\\u002d\\u002dclinic\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group alignfull appointment-cta__session-band--secondary appointment-cta__session-band--clinic\"><!-- wp:group {\"className\":\"appointment-cta__session\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group appointment-cta__session\"><!-- wp:columns {\"verticalAlignment\":\"top\",\"className\":\"appointment-cta__session-columns\"} -->\n<div class=\"wp-block-columns are-vertically-aligned-top appointment-cta__session-columns\"><!-- wp:column {\"verticalAlignment\":\"top\",\"className\":\"appointment-cta__session-content\"} -->\n<div class=\"wp-block-column is-vertically-aligned-top appointment-cta__session-content\"><!-- wp:heading {\"className\":\"appointment-cta__session-content__title\"} -->\n<h2 class=\"wp-block-heading appointment-cta__session-content__title\"><span><svg xmlns=\"http://www.w3.org/2000/svg\" width=\"24\" height=\"24\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\" class=\"lucide lucide-heart w-6 h-6 text-primary\"><path d=\"M19 14c1.49-1.46 3-3.21 3-5.5A5.5 5.5 0 0 0 16.5 3c-1.76 0-3 .5-4.5 2-1.5-1.5-2.74-2-4.5-2A5.5 5.5 0 0 0 2 8.5c0 2.3 1.5 4.05 3 5.5l7 7Z\"></path></svg></span>Séance au cabinet</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Prix d\'une séance : 50 €</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Accueil au cabinet sur rendez-vous uniquement. Merci d’arriver 5 minutes avant l’horaire prévu pour un échange serein.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Les séances durent environ 30 minutes. Un temps d’échange en début de séance permet d’adapter l’accompagnement.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Règlement en espèces, par carte bancaire ou chèque à l’ordre de « Aimer Guérir »</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"verticalAlignment\":\"top\",\"className\":\"appointment-cta__session-media\"} -->\n<div class=\"wp-block-column is-vertically-aligned-top appointment-cta__session-media\"><!-- wp:html -->\n<div class=\"appointment-cta__map\">\n            <iframe src